// ============================================================
// Drift Alert - Format Drift Report for Telegram
// ============================================================

const CHAT_ID = '{{ $env.TELEGRAM_CHAT_ID }}';

const items = $input.all();
const firstItem = items[0]?.json;
const today = new Date().toISOString().slice(0, 10);

// --- Case A: HTTP error ---
if (firstItem?.error || (firstItem?.statusCode && firstItem.statusCode >= 400)) {
  const errorMsg = firstItem.error?.message || firstItem.message || firstItem.error || 'Error desconocido';
  return [{
    json: {
      text: `<b>\ud83d\udcca Drift Report \u2014 Trading Memes</b>\n` +
            `<b>Fecha:</b> ${today}\n\n` +
            `\u274c <b>ERROR</b>: Fallo al consultar Supabase.\n` +
            `<code>${errorMsg}</code>\n\n` +
            `Verificar conectividad con Supabase y la tabla drift_reports.`,
      chat_id: CHAT_ID
    }
  }];
}

// --- Parse report ---
// exec_query returns array; n8n may wrap it or split into items
let report = null;
if (Array.isArray(firstItem)) {
  report = firstItem.length > 0 ? firstItem[0] : null;
} else if (firstItem && firstItem.checked_at) {
  report = firstItem;
} else if (firstItem && Array.isArray(firstItem.result)) {
  report = firstItem.result.length > 0 ? firstItem.result[0] : null;
}

// --- Case B: No drift report found ---
if (!report || !report.checked_at) {
  return [{
    json: {
      text: `<b>\ud83d\udcca Drift Report \u2014 Trading Memes</b>\n` +
            `<b>Fecha:</b> ${today}\n\n` +
            `\u2139\ufe0f No hay drift report disponible.\n` +
            `Verificar que check-retrain.yml se ejecut\u00f3 correctamente.`,
      chat_id: 'TELEGRAM_CHAT_ID'
    }
  }];
}

// --- Case C: Report found - format nicely ---
const r = report;

// Parse JSON fields if they come as strings
function safeParse(val) {
  if (!val) return null;
  if (typeof val === 'object') return val;
  try { return JSON.parse(val); } catch (e) { return null; }
}

const checkedAt = r.checked_at ? r.checked_at.slice(0, 19).replace('T', ' ') : 'N/A';
const modelVersion = r.model_version || 'N/A';
const overallScore = r.overall_score !== undefined ? Number(r.overall_score).toFixed(2) : 'N/A';
const needsRetrain = r.needs_retraining === true;

// Time drift
const timeDriftDays = r.time_drift_days !== undefined ? r.time_drift_days : 'N/A';
const timeDriftTriggered = r.time_drift_triggered === true;

// Volume drift
const volumeDriftNewLabels = r.volume_drift_new_labels !== undefined ? r.volume_drift_new_labels : 'N/A';
const volumeDriftTriggered = r.volume_drift_triggered === true;

// Feature drift
const featureDriftCount = r.feature_drift_count !== undefined ? r.feature_drift_count : 'N/A';
const featureDriftTotal = r.feature_drift_total !== undefined ? r.feature_drift_total : 'N/A';
const featureDriftTriggered = r.feature_drift_triggered === true;
const featureDriftDetails = safeParse(r.feature_drift_details);

// Reasons
const reasons = safeParse(r.reasons) || (r.reasons ? [r.reasons] : []);

// Build message
let msg = `<b>\ud83d\udcca Drift Report \u2014 Trading Memes</b>\n`;
msg += `<b>Fecha:</b> ${checkedAt}\n`;
msg += `<b>Modelo:</b> ${modelVersion}\n`;
msg += `<b>Score:</b> ${overallScore}/1.0\n`;
msg += `<b>Necesita retrain:</b> ${needsRetrain ? '\u2705 S\u00ed' : '\u274c No'}\n\n`;

msg += `<b>\u23f0 Time Drift:</b> ${timeDriftDays} d\u00edas ${timeDriftTriggered ? '\u26a0\ufe0f' : '\u2705'}\n`;
msg += `<b>\ud83d\udcc8 Volume Drift:</b> ${volumeDriftNewLabels} nuevos labels ${volumeDriftTriggered ? '\u26a0\ufe0f' : '\u2705'}\n`;
msg += `<b>\ud83d\udd2c Feature Drift:</b> ${featureDriftCount}/${featureDriftTotal} features desviadas ${featureDriftTriggered ? '\u26a0\ufe0f' : '\u2705'}\n`;

// Feature drift details
if (featureDriftDetails && typeof featureDriftDetails === 'object') {
  const entries = Array.isArray(featureDriftDetails) ? featureDriftDetails : Object.entries(featureDriftDetails);
  if (entries.length > 0) {
    msg += `\n<b>Features desviadas:</b>\n`;
    for (const entry of entries) {
      if (Array.isArray(entry)) {
        // Object.entries format: [feature_name, {train, current, shift_pct}]
        const [feature, detail] = entry;
        if (detail && typeof detail === 'object') {
          const train = detail.train !== undefined ? Number(detail.train).toFixed(3) : 'N/A';
          const current = detail.current !== undefined ? Number(detail.current).toFixed(3) : 'N/A';
          const shift = detail.shift_pct !== undefined ? Number(detail.shift_pct).toFixed(1) : 'N/A';
          msg += `\u2022 ${feature}: train=${train} \u2192 actual=${current} (${shift}%)\n`;
        } else {
          msg += `\u2022 ${feature}: ${detail}\n`;
        }
      } else if (typeof entry === 'object' && entry.feature) {
        // Array of objects format: [{feature, train, current, shift_pct}]
        const train = entry.train !== undefined ? Number(entry.train).toFixed(3) : 'N/A';
        const current = entry.current !== undefined ? Number(entry.current).toFixed(3) : 'N/A';
        const shift = entry.shift_pct !== undefined ? Number(entry.shift_pct).toFixed(1) : 'N/A';
        msg += `\u2022 ${entry.feature}: train=${train} \u2192 actual=${current} (${shift}%)\n`;
      }
    }
  }
}

// Retrain reasons
if (needsRetrain && Array.isArray(reasons) && reasons.length > 0) {
  msg += `\n<b>\ud83d\udd04 Razones:</b>\n`;
  for (const reason of reasons) {
    msg += `\u2022 ${reason}\n`;
  }
  msg += `\u26a1 Auto-retrain disparado.`;
}

return [{
  json: {
    text: msg,
    chat_id: CHAT_ID
  }
}];
